    NotfoundComponent,
    HomeComponent,
    EmpdetailsComponent,
    AddempComponent,
    HeaderComponent,
    FooterComponent
  ],
  imports: [
    BrowserModule,
    AppRoutingModule,
    FormsModule,
    HttpClientModule
  ],
  providers: [itle],
  bootstrap: [AppComponent]
})
export class AppModule { }
